-- Prompt 35: append-only records and scoped exports.
begin;set local role authenticated;select set_config('request.jwt.claim.role','authenticated',true);select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);
do $$declare exported jsonb;begin exported:=public.export_my_gym_data('30000000-0000-4000-8000-000000000001');if exported#>>'{profile,id}'<>auth.uid()::text or exists(select 1 from jsonb_array_elements(exported->'ascents')item where item->>'id'is null)then raise exception'Member export scope is invalid';end if;begin perform public.export_gym_operational_data('30000000-0000-4000-8000-000000000001');raise exception'Member created owner export';exception when insufficient_privilege then null;end;end$$;
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);do $$declare exported jsonb;begin exported:=public.export_gym_operational_data('30000000-0000-4000-8000-000000000001');if exported->'gym'->>'id'<>'30000000-0000-4000-8000-000000000001'or exported::text~'accepted_name|signature_text|guest_email'then raise exception'Owner export exposed disallowed personal data';end if;end$$;
set local role service_role;do $$declare audit_id uuid;begin select id into audit_id from public.audit_logs limit 1;begin update public.audit_logs set outcome='failed'where id=audit_id;raise exception'Audit record was edited';exception when insufficient_privilege then null;end;begin delete from public.audit_logs where id=audit_id;raise exception'Audit record was deleted';exception when insufficient_privilege then null;end;if not exists(select 1 from public.audit_logs where action='privacy.member_export.created')or not exists(select 1 from public.audit_logs where action='privacy.gym_export.created')then raise exception'Exports were not audited';end if;end$$;rollback;
